function getMessageTargetOrigin() {
    const origin = window.location && window.location.origin;
    return origin && origin !== 'null' && /^https?:\/\//i.test(origin) ? origin : '*';
}

function isTrustedWindowMessage(event, expectedWindow) {
    if (!event || !expectedWindow) {
        return false;
    }
    if (event.source && event.source !== expectedWindow) {
        return false;
    }
    if (!event.origin || event.origin === 'null') {
        return Boolean(window.location && window.location.protocol === 'file:');
    }
    const origin = window.location && window.location.origin;
    if (!origin || origin === 'null' || event.origin !== origin) {
        return false;
    }
    return true;
}

function summarizeSystemDiagnosticsErrorForLog(error) {
    if (!error || typeof error !== 'object') {
        return { name: typeof error };
    }
    const status = Number(error.status);
    return {
        name: typeof error.name === 'string' && error.name ? error.name.slice(0, 80) : 'Error',
        status: Number.isFinite(status) ? status : undefined
    };
}

function resolveTrustedDiagnosticUrl(rawUrl) {
    if (!rawUrl) {
        return '';
    }
    try {
        const baseHref = window.location && window.location.href ? window.location.href : 'http://localhost/';
        const resolved = new URL(String(rawUrl), baseHref);
        const protocol = (resolved.protocol || '').toLowerCase();

        if (protocol === 'http:' || protocol === 'https:') {
            const origin = window.location && window.location.origin;
            return origin && origin !== 'null' && resolved.origin === origin ? resolved.href : '';
        }

        if (protocol === 'file:' && window.location && window.location.protocol === 'file:') {
            return resolved.href;
        }
    } catch (_) {
        return '';
    }
    return '';
}

function escapeDiagnosticHtml(value) {
    if (value == null) {
        return '';
    }
    return String(value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');
}

function normalizeDiagnosticClassSuffix(value) {
    return String(value || '').replace(/[^a-z0-9_-]/gi, '') || 'unknown';
}

function formatDiagnosticNumber(value, fallback = 0) {
    const number = Number(value);
    return Number.isFinite(number) ? number : fallback;
}

const MAX_DIAGNOSTIC_EXAMS = 200;
const MAX_COMMUNICATION_TEST_EXAMS = 25;
const MAX_COMMUNICATION_CONCURRENCY = 5;
const VALIDATION_CONCURRENCY = 10;

function normalizeDiagnosticExamList(examIndex, maxItems = MAX_DIAGNOSTIC_EXAMS) {
    return Array.isArray(examIndex)
        ? examIndex.filter(Boolean).slice(0, maxItems)
        : [];
}

function normalizeDiagnosticExamIds(examIds) {
    return Array.isArray(examIds)
        ? examIds
            .map((examId) => String(examId || '').trim())
            .filter(Boolean)
            .slice(0, MAX_COMMUNICATION_TEST_EXAMS)
        : [];
}

function normalizeDiagnosticConcurrency(value, fallback = 3) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric) || numeric <= 0) {
        return fallback;
    }
    return Math.max(1, Math.min(MAX_COMMUNICATION_CONCURRENCY, Math.floor(numeric)));
}

async function runDiagnosticBatches(items, concurrency, worker) {
    const safeConcurrency = normalizeDiagnosticConcurrency(concurrency);
    const results = [];
    for (let i = 0; i < items.length; i += safeConcurrency) {
        const batch = items.slice(i, i + safeConcurrency);
        const batchResults = await Promise.all(batch.map(worker));
        results.push(...batchResults);
    }
    return results;
}

